BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?errorElem ?errorName ?dep ?depName ?role WHERE {
  ?errorElem rdf:type vocab:block .
  ?errorElem vocab:NamedElement_name ?errorName .
  FILTER(CONTAINS(LCASE(STR(?errorName)), LCASE("ErrorRollUpPatternElement")))

  OPTIONAL {
    ?dep rdf:type vocab:dependency .
  }
  OPTIONAL {
    ?dep vocab:NamedElement_name ?depName .
  }

  # Try to find dependencies that involve the roll-up element (either client or supplier)
  OPTIONAL {
    ?dep vocab:Dependency_client ?errorElem .
    BIND("client" AS ?role)
  }
  OPTIONAL {
    ?dep vocab:Dependency_supplier ?errorElem .
    BIND("supplier" AS ?role)
  }

  FILTER(BOUND(?dep))
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?budgetOwner ?budgetName ?client ?clientName ?supplier ?supplierName WHERE {
  ?errorElem rdf:type vocab:block .
  ?errorElem vocab:NamedElement_name ?errorName .
  FILTER(CONTAINS(LCASE(STR(?errorName)), LCASE("ErrorRollUpPatternElement")))

  ?dep rdf:type vocab:dependency .
  { ?dep vocab:Dependency_client ?errorElem . }
  UNION
  { ?dep vocab:Dependency_supplier ?errorElem . }

  OPTIONAL { ?dep vocab:Dependency_client ?client . }
  OPTIONAL { ?dep vocab:Dependency_supplier ?supplier . }

  OPTIONAL { ?client vocab:NamedElement_name ?clientName . }
  OPTIONAL { ?supplier vocab:NamedElement_name ?supplierName . }

  # Focus on anything that looks like error budget / residual / uncertainty
  OPTIONAL { 
    ?client vocab:NamedElement_name ?budgetName .
    BIND(?client AS ?budgetOwner)
  }
  FILTER(
    EXISTS { ?client vocab:NamedElement_name ?clientName . } ||
    EXISTS { ?supplier vocab:NamedElement_name ?supplierName . } ||
    EXISTS { ?client vocab:NamedElement_name ?budgetName . }
  )

  FILTER(
    (BOUND(?clientName) && (CONTAINS(LCASE(STR(?clientName)), "error") || CONTAINS(LCASE(STR(?clientName)), "budget"))) ||
    (BOUND(?supplierName) && (CONTAINS(LCASE(STR(?supplierName)), "error") || CONTAINS(LCASE(STR(?supplierName)), "budget")))
  )
}
LIMIT 25
